css:
/* B타입 전용 프리미엄 테마 선택 UI 스타일 */
.b-heading-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.b-title {
  color: #212121;
  font-size: 24px;
  font-weight: 700;
  line-height: 32px;
  font-family: 'Pretendard', sans-serif;
}

.b-desc {
  color: #777777;
  font-size: 15px;
  font-weight: 400;
  line-height: 22px;
  font-family: 'Pretendard', sans-serif;
}

.b-info-capsule {
  padding: 12px 16px;
  background: #EEEFFA;
  border-radius: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
  border: 1px dashed rgba(88, 93, 203, 0.15);
}

.info-name {
  color: #212121;
  font-size: 12px;
  font-weight: 700;
  font-family: 'Pretendard', sans-serif;
}

.info-details {
  color: #212121;
  font-size: 12px;
  font-weight: 400;
  font-family: 'Pretendard', sans-serif;
}

.theme-checkbox {
  width: 20px;
  height: 20px;
  border-radius: 4px;
  transition: all 0.2s ease;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
}

.theme-checkbox[data-state="off"] {
  background: white;
  border: 1px solid #DEDEDE;
}

.theme-checkbox[data-state="on"] {
  background: #585DCB;
  border: 1px solid #585DCB;
}

.theme-checkbox::after {
  content: '';
  width: 5px;
  height: 9px;
  border: solid #ffffff;
  border-width: 0 2px 2px 0;
  transform: rotate(45deg) scale(0);
  position: absolute;
  margin-bottom: 2px;
}

.theme-checkbox[data-state="on"]::after {
  transform: rotate(45deg) scale(1);
}

/* Premium Radio Component */
.theme-radio {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  flex-shrink: 0;
}

.theme-radio[data-state="off"] {
  background: #ffffff;
  border: 1px solid #DEDEDE;
}

.theme-radio[data-state="on"] {
  background: #ffffff;
  border: 1px solid #585DCB;
  box-shadow: 0 2px 6px rgba(88, 93, 203, 0.15);
  outline: 1px #585DCB solid;
  outline-offset: -1px;
}

.theme-radio::after {
  content: '';
  width: 10px;
  height: 10px;
  background: #585DCB;
  border-radius: 50%;
  transform: scale(0);
  transition: transform 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: absolute;
}

.theme-radio[data-state="on"]::after {
  transform: scale(1);
}

.theme-accordion-item {
  border-bottom: 1px solid #f1f5f9;
}

.theme-header-row {
  padding: 20px 8px;
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
}

.theme-title {
  flex: 1;
  font-size: 16px;
  font-weight: 700;
  font-family: 'Pretendard', sans-serif;
}

.category-card {
  padding: 16px;
  background: white;
  border-radius: 8px;
  outline: 1px #E8EAF3 solid;
  outline-offset: -1px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.sub-item-row {
  padding: 12px;
  background: #F6F6F6;
  border-radius: 8px;
  display: flex;
  align-items: center;
  gap: 10px;
  transition: background-color 0.2s ease;
}

.sub-item-row.checked-row {
  background: #EEEFFA;
}
